import React, { useState } from 'react';
import './AboutPage.css';

const AboutPage = () => {
  const [currentSlide, setCurrentSlide] = useState(0);

  // Carousel images
  const carouselImages = [
    '/about-image/carousel-about1.jpg',
    '/about-image/carousel-about2.jpg',
    '/about-image/carousel-about3.jpg',
    '/about-image/carousel-about4.jpg',
    '/about-image/carousel-about5.jpg',
    '/about-image/carousel-about6.jpg'
  ];

  const nextSlide = () => {
    setCurrentSlide((prev) => {
      const nextIndex = prev + 3;
      return nextIndex >= carouselImages.length ? 0 : nextIndex;
    });
  };

  const prevSlide = () => {
    setCurrentSlide((prev) => {
      const prevIndex = prev - 3;
      return prevIndex < 0 ? Math.max(0, carouselImages.length - 3) : prevIndex;
    });
  };

  const goToSlide = (index) => {
    setCurrentSlide(index);
  };
  const handleSocialMediaClick = (platform) => {
    let url;
    switch (platform) {
      case 'instagram':
        url = 'https://www.instagram.com/jeenas.kitchen/reels/';
        break;
      case 'youtube':
        url = 'https://www.youtube.com/@Jeena.s.kitchen';
        break;
      default:
        return;
    }
    window.open(url, '_blank', 'noopener,noreferrer');
  };

  const handleVideoClick = (videoUrl) => {
    window.open(videoUrl, '_blank', 'noopener,noreferrer');
  };

  const handleInstagramPostClick = (postUrl) => {
    window.open(postUrl, '_blank', 'noopener,noreferrer');
  };

  // Instagram reel data with custom thumbnails
  const instagramReels = [
    {
      id: 'C-5Pb10h-WQ',
      url: 'https://www.instagram.com/reel/C-5Pb10h-WQ/',
      thumbnail: '/modal-images/samgak-gimbap.jpg',
      title: 'Samgak Gimbap',
      description: 'Quick and easy triangular gimbap'
    },
    {
      id: 'C93-oOxx_yP', 
      url: 'https://www.instagram.com/p/C93-oOxx_yP/',
      thumbnail: '/modal-images/potato-salada-sandwich.jpg',
      title: 'Potato Salad Sandwich',
      description: 'Creamy potato salad sandwich'
    },
    {
      id: 'DGxHU5uRHfd',
      url: 'https://www.instagram.com/reel/DGxHU5uRHfd/',
      thumbnail: '/modal-images/strawberry-chap-sal-tteok.jpg',
      title: 'Strawberry Chap-sal-tteok',
      description: 'Sweet rice cake with strawberries'
    }
  ];

  const handleInstagramClick = (url) => {
    window.open(url, '_blank', 'noopener,noreferrer');
  };

  // YouTube URL parsing function
  const getYouTubeThumbnailUrl = (url, quality = 'mqdefault') => {
    if (!url) return '';
    const videoId = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&\n?#]+)/);
    return videoId ? `https://img.youtube.com/vi/${videoId[1]}/${quality}.jpg` : '';
  };

  // Instagram URL parsing function
  const getInstagramThumbnailUrl = (url) => {
    if (!url) return '';
    const postId = url.match(/instagram\.com\/(?:p|reel)\/([^\/\?#]+)/);
    if (postId) {
      const imageMap = {
        'C93-oOxx_yP': '/instagram/Potato Salada Sandwich.jpg',
        'C-5Pb10h-WQ': '/instagram/Samgak Gimbap.jpg',
        'DGxHU5uRHfd': '/instagram/Strawberry Chap-sal-tteok.jpg',
        'DIiF1FuRqQY': '/instagram/Tofu Inseolmi.jpg',
      };
      return imageMap[postId[1]] || null;
    }
    return null;
  };

  // YouTube video URLs
  const youtubeVideoUrls = [
    'https://youtu.be/bJgz1qTa8Cg',
    'https://youtu.be/naS9csQ4inA'
  ];

  // Instagram post URLs
  const instagramPostUrls = [
    'https://www.instagram.com/p/C93-oOxx_yP/?utm_source=ig_web_copy_link&igsh=c2N4c3lscTBmbTE=',
    'https://www.instagram.com/reel/C-5Pb10h-WQ/?utm_source=ig_web_copy_link&igsh=bnpwc201dXRoNjN6',
    'https://www.instagram.com/reel/DGxHU5uRHfd/?utm_source=ig_web_copy_link&igsh=dnBhdzg4c2g2ZDY=',
    'https://www.instagram.com/reel/DIiF1FuRqQY/?utm_source=ig_web_copy_link&igsh=MXZwYzJicGhubWo4bA=='
  ];

  // Generate thumbnail URLs
  const youtubeThumbnails = youtubeVideoUrls.map(url => getYouTubeThumbnailUrl(url, 'mqdefault'));
  const instagramThumbnails = instagramPostUrls.map(url => getInstagramThumbnailUrl(url));

  return (
    <div className="about-page">
      <div className="about-page-content">
        {/* Hero Section with Background Image */}
        <div className="about-hero" style={{ backgroundImage: 'url(/about-image/hero-about.jpg)' }}>
          <div className="about-hero-overlay"></div>
        </div>

        {/* Main Content */}
        <div className="about-main-content">
          {/* Paragraph 1 - Text Left, Image Right */}
          <div className="about-section text-left">
            <div className="about-text">
              <h1 className="about-title">
                Welcome to<br/>
                <span className="korean-title">Jeena's Kitchen 지나키친</span>
              </h1>
              <p>
                Hello, and welcome to Jeena's Kitchen.

I was born and raised in Korea, and I moved to Australia 11 years ago.

For me, sharing the food I cook is more than just a conversation — it feels like a deep connection.

A meal prepared with care can be an act of self-love, a source of comfort, and at the same time, a tender expression of affection toward family and friends.

Even with cultural differences, food has allowed me to build bridges — to grow closer to friends and colleagues, and to create a sense of intimacy.

No matter how tough the day was, cooking has always been a moment of healing for me
              </p>
            </div>
            <div className="about-image">
              <img src="/about-image/para-about-1.jpg" alt="Jeena in Australia" />
            </div>
          </div>

          {/* Paragraph 2 - Image Left, Text Right */}
          <div className="about-section image-left">
            <div className="about-image">
              <img src="/about-image/para-about-2.jpg" alt="Cooking and self-discovery" />
            </div>
            <div className="about-text">
              <p>
                <strong>Rediscover myself through cooking</strong><br/>
                Jeena's Kitchen is a space where I explore the thoughts, stories, and flavours that have shaped me — especially between the different cultural identities I've come to hold. When I first came to study abroad, my goals were simple: finish school, find a job. Living in a new country with an unfamiliar system, I constantly tried to adapt — reading the room, meeting expectations, doing what was needed to "fit in." But in the process, I slowly began to lose sight of who I really was. That's when questions began to bubble up:
              </p>
            </div>
          </div>

          {/* Paragraph 3 - Text Left, Image Right */}
          <div className="about-section text-left">
            <div className="about-text">
              <p>
                <strong>Connect to people in the world</strong><br/>
                Through cooking Korean food, I found a way to reconnect with my roots. I also found new ways of telling stories — not just to others, but to myself. Jeena's Kitchen is like a small lab where I explore how to relate to myself, to others, and to society in a healthier way. It's a space where I build my own little universe — through food.
              </p>
            </div>
            <div className="about-image">
              <img src="/about-image/para-about-3.jpg" alt="Kitchen stories" />
            </div>
          </div>

          {/* Paragraph 4 - Image Left, Text Right */}
          <div className="about-section image-left">
            <div className="about-image">
              <img src="/about-image/para-about-4.jpg" alt="Community and cooking" />
            </div>
            <div className="about-text">
              <p>
                <strong>Cooking can be a fun "play"</strong><br/>
                Whether you're missing your mom's food, looking for comfort while eating alone, or simply moving through life at your own pace — I hope Jeena's Kitchen can be a small moment of rest for you. For now, I mostly focus on Korean dishes. But I hope to gently open the door to recipes from all kinds of cultures, and share the joy of inclusive cooking with many more people. Most of all, I hope this becomes a space where a warm, caring community can grow — one meal at a time.
              </p>
            </div>
          </div>

          {/* Carousel Section - 3 Images Visible */}
          <div className="carousel-section">
            <div className="carousel-container">
              <button className="carousel-arrow carousel-arrow-left" onClick={prevSlide}>
                <svg width="24" height="24" viewBox="0 0 24 24" fill="white">
                  <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
                </svg>
              </button>

              <div className="carousel-track">
                {carouselImages.slice(currentSlide, currentSlide + 3).map((image, index) => (
                  <div
                    key={currentSlide + index}
                    className="carousel-slide"
                  >
                    <img src={image} alt={`Carousel ${currentSlide + index + 1}`} />
                  </div>
                ))}
              </div>

              <button className="carousel-arrow carousel-arrow-right" onClick={nextSlide}>
                <svg width="24" height="24" viewBox="0 0 24 24" fill="white">
                  <path d="M8.59 16.59L10 18l6-6-6-6-1.41 1.41L13.17 12z"/>
                </svg>
              </button>
            </div>

            <div className="carousel-dots">
              {[0, 3].map((startIndex) => (
                <button
                  key={startIndex}
                  className={`carousel-dot ${currentSlide === startIndex ? 'active' : ''}`}
                  onClick={() => goToSlide(startIndex)}
                />
              ))}
            </div>
          </div>
        </div>

        {/* Social Media Section */}
        <div className="social-media-section">
          <div className="social-media-container">
            <div className="embeds-grid">
              {/* YouTube Videos Grid */}
              <div className="youtube-videos-section">
                <h3>Watch My Latest Videos</h3>
                <div className="youtube-grid">
                  {/* Row 1 */}
                  <div className="youtube-row">
                    <div className="youtube-embed-item">
                      <iframe
                        width="100%"
                        height="auto"
                        src="https://www.youtube.com/embed/bJgz1qTa8Cg"
                        title="Korean Gimbap Video"
                        frameBorder="0"
                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                        allowFullScreen
                      ></iframe>
                    </div>
                    <div className="youtube-embed-item">
                      <iframe
                        width="100%"
                        height="auto"
                        src="https://www.youtube.com/embed/WjNX3pNa9Oo"
                        title="Korean Cooking Video 2"
                        frameBorder="0"
                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                        allowFullScreen
                      ></iframe>
                    </div>
                  </div>

                  {/* Row 2 */}
                  <div className="youtube-row">
                    <div className="youtube-embed-item">
                      <iframe
                        width="100%"
                        height="auto"
                        src="https://www.youtube.com/embed/naS9csQ4inA"
                        title="Korean Cooking Video 3"
                        frameBorder="0"
                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                        allowFullScreen
                      ></iframe>
                    </div>
                    <div className="youtube-embed-item">
                      <iframe
                        width="100%"
                        height="auto"
                        src="https://www.youtube.com/embed/w_QVOV3VJwY"
                        title="Korean Cooking Video 4"
                        frameBorder="0"
                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                        allowFullScreen
                      ></iframe>
                    </div>
                  </div>
                </div>
              </div>

              {/* Instagram Reels with Custom Thumbnails */}
              <div className="instagram-reels-section">
                <h3>Follow on Instagram</h3>
                <div className="instagram-reels-grid">
                  {instagramReels.map((reel, index) => (
                    <div 
                      key={reel.id}
                      className="instagram-reel-item"
                      onClick={() => handleInstagramClick(reel.url)}
                    >
                      <div className="reel-thumbnail-container">
                        <img 
                          src={reel.thumbnail}
                          alt={reel.title}
                          className="reel-thumbnail"
                        />
                        <div className="reel-overlay">
                          <div className="instagram-icon">
                            <svg width="24" height="24" viewBox="0 0 24 24" fill="white">
                              <path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zm0-2.163c-3.259 0-3.667.014-4.947.072-4.358.2-6.78 2.618-6.98 6.98-.059 1.281-.073 1.689-.073 4.948 0 3.259.014 3.668.072 4.948.2 4.358 2.618 6.78 6.98 6.98 1.281.058 1.689.072 4.948.072 3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98-1.281-.059-1.69-.073-4.949-.073zm0 5.838c-3.403 0-6.162 2.759-6.162 6.162s2.759 6.163 6.162 6.163 6.162-2.759 6.162-6.163c0-3.403-2.759-6.162-6.162-6.162zm0 10.162c-2.209 0-4-1.79-4-4 0-2.209 1.791-4 4-4s4 1.791 4 4c0 2.21-1.791 4-4 4zm6.406-11.845c-.796 0-1.441.645-1.441 1.44s.645 1.44 1.441 1.44c.795 0 1.439-.645 1.439-1.44s-.644-1.44-1.439-1.40z"/>
                            </svg>
                          </div>
                          <div className="play-button">
                            <svg width="32" height="32" viewBox="0 0 24 24" fill="white">
                              <path d="M8 5v14l11-7z"/>
                            </svg>
                          </div>
                        </div>
                      </div>
                      <div className="reel-info">
                        <h4 className="reel-title">{reel.title}</h4>
                        <p className="reel-description">{reel.description}</p>
                      </div>
                    </div>
                  ))}
                </div>

                {/* Instagram Follow Button */}
                <div className="instagram-follow-section">
                  <a 
                    href="https://www.instagram.com/jeenas.kitchen/"
                    target="_blank"
                    rel="noopener noreferrer"
                    className="instagram-follow-button"
                  >
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                      <path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zm0-2.163c-3.259 0-3.667.014-4.947.072-4.358.2-6.78 2.618-6.98 6.98-.059 1.281-.073 1.689-.073 4.948 0 3.259.014 3.668.072 4.948.2 4.358 2.618 6.78 6.98 6.98 1.281.058 1.689.072 4.948.072 3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98-1.281-.059-1.69-.073-4.949-.073zm0 5.838c-3.403 0-6.162 2.759-6.162 6.162s2.759 6.163 6.162 6.163 6.162-2.759 6.162-6.163c0-3.403-2.759-6.162-6.162-6.162zm0 10.162c-2.209 0-4-1.79-4-4 0-2.209 1.791-4 4-4s4 1.791 4 4c0 2.21-1.791 4-4 4zm6.406-11.845c-.796 0-1.441.645-1.441 1.44s.645 1.44 1.441 1.44c.795 0 1.439-.645 1.439-1.40s-.644-1.44-1.439-1.40z"/>
                    </svg>
                    Follow @jeenas.kitchen
                  </a>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AboutPage;
